const createAutoplayControl = (options: Record<string, unknown> = {}) => {
  const config = { ...options };
  let playing = Boolean(config.playOnInit);
  const control: AutoplayControl = {
    options: config,
    play: jest.fn(() => {
      playing = true;
    }),
    stop: jest.fn(() => {
      playing = false;
    }),
    reset: jest.fn(),
    isPlaying: jest.fn(() => playing)
  };
  return control;
};

