const slides = Array.from({ length: 5 }, (_, index) => (
  <div key={`slide-${index}`} data-testid={`slide-${index}`}>
    Slide {index + 1}
  </div>
));

const renderCarousel = (
  props: Partial<CarouselProps> = {},
  customChildren: React.ReactNode = slides
): RenderResult =>
  render(
    <Carousel ariaLabel="Stories" {...props}>
      {customChildren}
    </Carousel>
  );

const ContextInvoker: React.FC<{
  onInvoke: (context: ReturnType<typeof useCarouselContext>) => void;
  once?: boolean;
}> = ({ onInvoke, once = true }) => {
  const context = useCarouselContext();
  const executedRef = React.useRef(false);

  React.useEffect(() => {
    if (once && executedRef.current) {
      return;
    }
    if (once) {
      executedRef.current = true;
    }
    onInvoke(context);
  }, [context, onInvoke, once]);

  return null;
};

type CarouselContextSnapshot = ReturnType<typeof useCarouselContext>;

function assertContext(
  context: CarouselContextSnapshot | null,
  message: string
): CarouselContextSnapshot {
  if (!context) {
    throw new Error(message);
  }
  return context;
}

function assertAutoPlayControls(
  controls: CarouselContextSnapshot['autoPlay'],
  message: string
): NonNullable<CarouselContextSnapshot['autoPlay']> {
  if (!controls) {
    throw new Error(message);
  }
  return controls;
}

