it('throws when useCarouselContext is called outside of Carousel', () => {
  const Consumer: React.FC = () => {
    useCarouselContext();
    return null;
  };

  expect(() => render(<Consumer />)).toThrow(
    'useCarouselContext must be used within a <Carousel> instance.'
  );
});

